                  </div>

                  {/* Operator Performance Grid */}
                  <h4 style={{ fontSize: '1.2rem', color: '#fff', marginBottom: '12px', marginTop: '24px', borderBottom: '1px solid rgba(255,255,255,0.1)', paddingBottom: '6px' }}>
