                      {/* Glowing fiber signal */}
                      <div
                        style={{
                          position: 'absolute',
                          top: '4px',
                          left: '6px',
                          height: '6px',
                          width: `calc(${(timeLeft / timeLimit) * 100}% - 12px)`,
                          minWidth: '2px',
                          borderRadius: '3px',
                          background: `linear-gradient(90deg, transparent, ${getTimerColor()})`,
                          boxShadow: `0 0 10px ${getTimerColor()}, 0 0 4px #fff`,
                          transition: 'width 0.1s linear',
