                        </div>
                      )}
                    </div>
                  </div>

                  {/* Answer Control Modes: Multiple Choice (L) vs Numerical Keyboard (R) */}
                  <div className="main-layout-grid" style={{ width: '100%' }}>

                    {/* Multiple Choice Card */}
