                          onClick={() => { setExtraQuestion(prev => prev ? { ...prev, selected: opt } : null); }}
                          style={{
                            width: '100%',
                            textAlign: 'left',
                            padding: '12px',
                            borderRadius: '6px',
                            border: `1.5px solid ${border}`,
