                              borderColor: canAccept ? 'var(--neon-cyan)' : 'rgba(255,255,255,0.1)',
                              background: canAccept ? 'rgba(0, 255, 204, 0.15)' : 'rgba(255,255,255,0.05)',
                              color: canAccept ? '#fff' : 'rgba(255,255,255,0.3)',
                              cursor: canAccept ? 'pointer' : 'not-allowed',
                            }}
                          >
                            {canAccept ? '🤝 Aceitar Troca' : '⚠️ Requisitos insuficientes'}
                          </button>
                        )}
                      </div>
                    </div>
                  );
                })
              )}
            </div>
          </div>
        )}

        {/* Right Side: Inventory */}
        <div className="cyber-card" style={{ display: 'flex', flexDirection: 'column' }}>
          <h2 style={{ fontSize: '1.4rem', borderBottom: '1px solid rgba(255,255,255,0.1)', paddingBottom: '10px', marginBottom: '16px' }}>
            Seus Pets ({pets.length})
          </h2>

          {/* New Filters UI Block */}
          {pets.length > 0 && (
            <div style={{ display: 'flex', flexDirection: 'column', gap: '8px', marginBottom: '16px', background: 'rgba(255,255,255,0.02)', padding: '10px', borderRadius: '6px', border: '1px solid rgba(255,255,255,0.05)' }}>
              <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', gap: '10px' }}>
                <span style={{ fontSize: '0.75rem', fontWeight: 800, color: 'rgba(255,255,255,0.5)', minWidth: '60px' }}>Raridade:</span>
                <select
                  value={filterRarity}
                  onChange={(e) => { setFilterRarity(e.target.value); }}
                  style={{
                    flex: 1,
                    background: '#030712',
                    border: '1px solid rgba(255,255,255,0.15)',
                    borderRadius: '4px',
                    color: '#fff',
                    padding: '4px 8px',
                    fontSize: '0.8rem',
                    outline: 'none'
                  }}
                >
                  <option value="all">Todos</option>
                  <option value="common">Common</option>
                  <option value="rare">Rare</option>
                  <option value="epic">Epic</option>
                  <option value="legendary">Legendary</option>
                </select>
              </div>

              <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', gap: '10px' }}>
                <span style={{ fontSize: '0.75rem', fontWeight: 800, color: 'rgba(255,255,255,0.5)', minWidth: '60px' }}>Elemento:</span>
                <select
                  value={filterElement}
                  onChange={(e) => { setFilterElement(e.target.value); }}
                  style={{
                    flex: 1,
                    background: '#030712',
                    border: '1px solid rgba(255,255,255,0.15)',
                    borderRadius: '4px',
                    color: '#fff',
                    padding: '4px 8px',
                    fontSize: '0.8rem',
                    outline: 'none'
                  }}
                >
                  <option value="all">Todos</option>
                  <option value="fire">Fogo 🔥</option>
                  <option value="electric">Raio ⚡</option>
                  <option value="ice">Gelo ❄️</option>
                  <option value="cosmic">Cósmico 🌌</option>
                  <option value="none">Nenhum</option>
                </select>
              </div>
            </div>
          )}

          {pets.length === 0 ? (
            <div style={{ flex: 1, display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', color: 'rgba(255,255,255,0.65)', padding: '40px' }}>
              <span style={{ fontSize: '2.5rem', marginBottom: '10px' }}>🎒</span>
              <p style={{ fontStyle: 'italic' }}>Sua mochila de pets está vazia.</p>
              <p style={{ fontSize: '0.85rem', marginTop: '6px' }}>Gaste suas Gemas Matemáticas para abrir um ovo!</p>
            </div>
          ) : (
            <div style={{ display: 'flex', flexDirection: 'column', gap: '10px', maxHeight: '420px', overflowY: 'auto', paddingRight: '4px' }}>
              {pets
                .filter(pet => {
                  if (filterRarity !== 'all' && pet.rarity !== filterRarity) return false;
                  if (filterElement !== 'all') {
                    const petElem = getPetElement(pet.nickname);
                    if (filterElement !== petElem) return false;
                  }
                  return true;
                })
                .map(pet => {
                const isEquipped = gameState.equippedPetId === pet.id;
                const petType = PET_TYPES.find(p => p.id === pet.petTypeId);
                const rarityColor = getRarityColor(pet.rarity);

                return (
                  <div
                    key={pet.id}
                    style={{
                      display: 'flex',
                      alignItems: 'center',
                      justifyContent: 'space-between',
                      padding: '12px 16px',
                      borderRadius: '8px',
                      background: isEquipped ? 'rgba(0, 255, 204, 0.08)' : 'rgba(15, 23, 42, 0.4)',
                      border: isEquipped ? '1.5px solid var(--neon-cyan)' : '1px solid rgba(255, 255, 255, 0.05)',
                    }}
                  >
                    <div style={{ display: 'flex', alignItems: 'center', gap: '14px' }}>
                      <span
                        className={isEquipped ? 'animate-float' : ''}
                        style={{ fontSize: '2.2rem', display: 'inline-block' }}
                      >
                        {getPetEvolutionEmoji(petType?.emoji || '🐶', pet.level)}
                      </span>
                      <div>
                        <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
                          <span style={{ fontWeight: 800, fontSize: '1.05rem', color: '#fff' }}>
                            {pet.nickname}
                          </span>
                          <span style={{ fontSize: '0.75rem', color: pet.level === 2 ? 'var(--neon-yellow)' : 'rgba(255,255,255,0.5)', fontWeight: 800 }}>
                            Lvl {pet.level}
                          </span>
                          <span
                            style={{
                              fontSize: '0.65rem',
                              fontWeight: 900,
                              textTransform: 'uppercase',
                              padding: '2px 6px',
                              borderRadius: '4px',
                              backgroundColor: rarityColor + '20',
                              color: rarityColor,
                              border: `1px solid ${rarityColor}40`,
                            }}
                          >
                            {pet.rarity}
                          </span>
                        </div>
                        <div style={{ fontSize: '0.8rem', color: 'rgba(255,255,255,0.6)', marginTop: '3px' }}>
                          Buff: {getBuffDescription(pet)}
                        </div>
                      </div>
                    </div>

                    {activeTab === 'trade' ? (
                      pet.level > 1 ? (
                        <span style={{ fontSize: '0.8rem', color: 'rgba(255,255,255,0.65)', alignSelf: 'center' }}>
                          Evoluído Não Negociável
                        </span>
                      ) : (
                        <button
                          className="cyber-btn"
                          onClick={() => {
                            audioEngine.playCorrect();
                            setSelectedOfferPetId(selectedOfferPetId === pet.id ? null : pet.id);
                          }}
                          style={{
                            padding: '8px 12px',
                            fontSize: '0.8rem',
                            borderColor: selectedOfferPetId === pet.id ? 'var(--neon-cyan)' : 'rgba(0, 255, 204, 0.4)',
                            background: selectedOfferPetId === pet.id ? 'rgba(0, 255, 204, 0.2)' : 'rgba(15, 23, 42, 0.6)',
                          }}
                        >
                          {selectedOfferPetId === pet.id ? 'Selecionado' : 'Oferecer Pet'}
                        </button>
                      )
                    ) : activeTab === 'fusion' ? (
                      pet.level >= 6 ? (
                        <span style={{ fontSize: '0.8rem', color: 'var(--neon-yellow)', fontWeight: 800, alignSelf: 'center' }}>
                          ★ MÁXIMO
                        </span>
                      ) : (
                        <div style={{ display: 'flex', gap: '6px' }}>
                          <button
                            className="cyber-btn"
                            disabled={selectedPet2Id === pet.id}
                            onClick={() => {
                              audioEngine.playHatchRoll();
                              setSelectedPet1Id(selectedPet1Id === pet.id ? null : pet.id);
                            }}
                            style={{
                              padding: '6px 10px',
                              fontSize: '0.75rem',
                              borderWidth: selectedPet1Id === pet.id ? '2px' : '1px',
                              borderColor: selectedPet1Id === pet.id ? 'var(--neon-purple)' : 'rgba(0, 255, 204, 0.4)',
                              background: selectedPet1Id === pet.id ? 'rgba(168, 85, 247, 0.2)' : 'rgba(0, 255, 204, 0.1)',
                            }}
                          >
                            Slot 1
                          </button>
                          <button
                            className="cyber-btn"
                            disabled={selectedPet1Id === pet.id}
                            onClick={() => {
                              audioEngine.playHatchRoll();
                              setSelectedPet2Id(selectedPet2Id === pet.id ? null : pet.id);
                            }}
                            style={{
                              padding: '6px 10px',
                              fontSize: '0.75rem',
                              borderWidth: selectedPet2Id === pet.id ? '2px' : '1px',
                              borderColor: selectedPet2Id === pet.id ? 'var(--neon-purple)' : 'rgba(244, 63, 94, 0.4)',
                              background: selectedPet2Id === pet.id ? 'rgba(168, 85, 247, 0.2)' : 'rgba(244, 63, 94, 0.1)',
                            }}
                          >
                            Slot 2
                          </button>
                        </div>
                      )
                    ) : (
                      <div style={{ display: 'flex', gap: '8px' }}>
                        <button
                          className={`cyber-btn ${isEquipped ? 'cyber-btn-pink' : 'cyber-btn-cyan'}`}
                          onClick={() => handleEquip(pet.id)}
                          style={{ padding: '8px 14px', fontSize: '0.85rem' }}
                        >
                          {isEquipped ? 'Desequipar' : 'Equipar'}
                        </button>
                        <button
                          onClick={() => handleRelease(pet.id)}
                          style={{
                            background: 'none',
                            border: 'none',
                            color: 'var(--neon-pink)',
                            cursor: 'pointer',
                            fontSize: '0.85rem',
                            padding: '0 8px',
                          }}
                        >
                          Libertar 💸
                        </button>
                      </div>
                    )}
                  </div>
                );
              })}
            </div>
          )}
        </div>
      </div>
      )}

      {/* Hatch Overlay / Modal Animation */}
      {isHatching && (
        <div
          className={hatchStage === 'shaking' ? 'screen-shake-anim' : ''}
          style={{
            position: 'fixed',
            top: 0,
            left: 0,
            right: 0,
            bottom: 0,
            backgroundColor: 'rgba(3, 7, 18, 0.95)',
            zIndex: 999,
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
          }}
        >
          <style>{`
            @keyframes cyber-hatch-shake {
              0% { transform: translate(0, 0) rotate(0deg) scale(1); filter: drop-shadow(0 0 5px rgba(251, 113, 133, 0.5)); }
              10% { transform: translate(-4px, -2px) rotate(-3deg) scale(1.05); filter: drop-shadow(0 0 15px rgba(251, 113, 133, 0.8)); }
              20% { transform: translate(3px, 2px) rotate(4deg); }
              30% { transform: translate(-5px, 0px) rotate(-4deg); }
              40% { transform: translate(4px, -1px) rotate(3deg) scale(1.1); filter: drop-shadow(0 0 25px rgba(234, 179, 8, 0.9)); }
              50% { transform: translate(-3px, 2px) rotate(-3deg); }
              60% { transform: translate(4px, 1px) rotate(4deg); }
              70% { transform: translate(-4px, -2px) rotate(-4deg) scale(1.15); }
              80% { transform: translate(3px, 2px) rotate(3deg); }
              90% { transform: translate(-2px, -1px) rotate(-2deg); }
              100% { transform: translate(0, 0) rotate(0deg) scale(1.2); filter: drop-shadow(0 0 40px rgba(234, 179, 8, 1)); }
            }

            @keyframes cyber-hatch-glow {
              0% { transform: rotate(0deg) scale(1.2); filter: drop-shadow(0 0 20px rgba(168, 85, 247, 0.6)); }
              50% { transform: rotate(180deg) scale(1.4); filter: drop-shadow(0 0 50px rgba(236, 72, 153, 1)); }
              100% { transform: rotate(360deg) scale(1.6); filter: drop-shadow(0 0 80px rgba(253, 224, 71, 1)); }
            }

            @keyframes cyber-reveal-burst {
              0% { transform: scale(0.1) rotate(-45deg); opacity: 0; filter: brightness(3) blur(10px); }
              50% { transform: scale(1.3) rotate(10deg); opacity: 0.9; filter: brightness(1.5) blur(0px); }
              75% { transform: scale(0.9) rotate(-5deg); opacity: 1; }
              100% { transform: scale(1) rotate(0deg); opacity: 1; }
            }

            @keyframes screen-shake-severe {
              0%, 100% { transform: translate(0, 0); }
              10% { transform: translate(-4px, -4px); }
              20% { transform: translate(4px, 3px); }
              30% { transform: translate(-4px, 4px); }
              40% { transform: translate(3px, -3px); }
              50% { transform: translate(-4px, 3px); }
              60% { transform: translate(4px, -3px); }
              70% { transform: translate(-3px, 4px); }
              80% { transform: translate(3px, -4px); }
              90% { transform: translate(-4px, 3px); }
            }

            @keyframes particle-drift {
              0% { transform: translate(0, 0) scale(1); opacity: 0; }
              10% { opacity: 1; }
              90% { opacity: 1; }
              100% { transform: translate(var(--tx), var(--ty)) scale(0.5); opacity: 0; }
            }

            .screen-shake-anim {
              animation: screen-shake-severe 0.25s infinite;
            }

            .cyber-hatch-shake-class {
              animation: cyber-hatch-shake 0.35s infinite;
            }

            .cyber-hatch-glow-class {
              animation: cyber-hatch-glow 1.2s infinite linear;
            }

            .cyber-reveal-burst-class {
              animation: cyber-reveal-burst 0.75s cubic-bezier(0.175, 0.885, 0.32, 1.275) forwards;
            }

            .confetti-particle {
              position: absolute;
              animation: particle-drift 1.8s ease-out forwards;
              font-size: 1.5rem;
              pointer-events: none;
            }
          `}</style>

          <div
            className="cyber-card"
            style={{
              width: '90%',
              maxWidth: '450px',
              textAlign: 'center',
              padding: '40px 30px',
              border: hatchStage === 'shaking' ? '2px solid var(--neon-pink)' : hatchStage === 'spinning' ? '2px solid var(--neon-purple)' : '2px solid var(--neon-yellow)',
              boxShadow: hatchStage === 'shaking' ? '0 0 35px rgba(244, 63, 94, 0.3)' : hatchStage === 'spinning' ? '0 0 35px rgba(168, 85, 247, 0.3)' : '0 0 35px rgba(234, 179, 8, 0.4)',
              transition: 'all 0.3s ease',
              position: 'relative',
              overflow: 'hidden'
            }}
          >
            {hatchStage === 'shaking' && (
              <div>
                <h2 className="text-glow-pink" style={{ color: 'var(--neon-pink)', fontSize: '1.8rem', marginBottom: '24px' }}>
                  Comprando Ovo Matemático...
                </h2>
                <div
                  className="cyber-hatch-shake-class"
                  style={{
                    fontSize: '6rem',
                    margin: '30px 0',
                    display: 'inline-block',
                  }}
                >
                  {getEggEmoji(eggTypeSelected)}
                </div>
                <p style={{ color: 'rgba(255,255,255,0.7)' }}>Prepare-se! O ovo está prestes a quebrar...</p>
              </div>
            )}

            {hatchStage === 'spinning' && (
              <div style={{ position: 'relative' }}>
                <div
                  style={{
                    position: 'absolute',
                    top: '50%',
                    left: '50%',
                    transform: 'translate(-50%, -50%)',
                    width: '200px',
                    height: '200px',
                    borderRadius: '50%',
                    background: 'radial-gradient(circle, rgba(168, 85, 247, 0.2) 0%, transparent 70%)',
                    animation: 'pulse-ring 1.5s infinite alternate',
                    zIndex: 0
                  }}
                />
                <h2 className="text-glow-purple" style={{ color: 'var(--neon-purple)', fontSize: '1.8rem', marginBottom: '24px', position: 'relative', zIndex: 1 }}>
                  Rachando o Ovo...
                </h2>
                <div
                  className="cyber-hatch-glow-class"
                  style={{
                    fontSize: '6rem',
                    margin: '30px 0',
                    display: 'inline-block',
                    position: 'relative',
                    zIndex: 1
                  }}
                >
                  {spinEmoji}
                </div>
                <p style={{ color: 'rgba(255,255,255,0.7)', position: 'relative', zIndex: 1 }}>Calculando probabilidade cósmica...</p>
              </div>
            )}

            {hatchStage === 'revealed' && hatchedPet && (
              <div style={{ position: 'relative' }}>
                {/* Emitter of emoji sparks / confetti */}
                {Array.from({ length: 15 }).map((_, i) => {
                  const tx = (Math.random() - 0.5) * 260 + 'px';
                  const ty = -100 - Math.random() * 120 + 'px';
                  const delay = Math.random() * 0.4 + 's';
                  const emojis = ['✨', '⭐', '🎉', '💥', '🌟', '🍭', '💖'];
                  const randomEmoji = emojis[i % emojis.length];
                  return (
                    <span
                      key={i}
                      className="confetti-particle"
                      style={{
                        left: '50%',
                        top: '40%',
                        animationDelay: delay,
                        '--tx': tx,
                        '--ty': ty,
                      } as React.CSSProperties}
                    >
                      {randomEmoji}
                    </span>
                  );
                })}

                <h2
                  className="text-glow-yellow"
                  style={{
                    color: getRarityColor(hatchedPet.rarity),
                    fontSize: '2rem',
                    marginBottom: '10px',
                    textTransform: 'uppercase',
                  }}
                >
                  ¡PET DESBLOQUEADO!
                </h2>

                <div style={{ fontSize: '7rem', margin: '20px 0' }} className="cyber-reveal-burst-class">
                  {PET_TYPES.find(p => p.id === hatchedPet.petTypeId)?.emoji}
                </div>

                <div
                  style={{
                    display: 'inline-block',
                    padding: '4px 12px',
                    borderRadius: '20px',
                    fontSize: '0.8rem',
                    fontWeight: 900,
                    textTransform: 'uppercase',
                    backgroundColor: getRarityColor(hatchedPet.rarity) + '20',
                    color: getRarityColor(hatchedPet.rarity),
                    border: `1.5px solid ${getRarityColor(hatchedPet.rarity)}40`,
                    marginBottom: '16px',
                  }}
                >
                  {hatchedPet.rarity}
                </div>

                <h3 style={{ fontSize: '1.5rem', marginBottom: '8px', color: '#fff' }}>
                  {hatchedPet.nickname}
                </h3>

                <p style={{ color: 'var(--neon-cyan)', fontWeight: 600, fontSize: '0.95rem', marginBottom: '24px' }}>
                  Bônus: {getBuffDescription(hatchedPet)}
                </p>

                {/* Nickname modification */}
                <div style={{ marginBottom: '24px', textAlign: 'left' }}>
                  <label style={{ display: 'block', fontSize: '0.85rem', marginBottom: '6px', color: 'rgba(255,255,255,0.7)' }}>
                    Dê um apelido personalizado para o seu pet:
                  </label>
                  <input
                    type="text"
                    value={petNicknameInput}
                    onChange={(e) => { setPetNicknameInput(e.target.value); }}
                    placeholder="Apelido do pet"
                    maxLength={15}
                    style={{
                      width: '100%',
                      padding: '10px',
                      borderRadius: '6px',
                      border: '1px solid rgba(255,255,255,0.2)',
                      backgroundColor: '#0b0f19',
                      color: '#fff',
                      fontSize: '1rem',
                      textAlign: 'center',
                    }}
                  />
                </div>

                <button
                  className="cyber-btn"
                  onClick={saveNickname}
                  style={{
                    padding: '12px 30px',
                    fontSize: '1rem',
                    fontWeight: 800,
                    width: '100%',
                  }}
                >
                  Salvar e Equipar Pet ➔
                </button>
              </div>
            )}
          </div>
        </div>
      )}

      {/* Level Up Overlay */}
      {levelUpMessage && (
        <div
          style={{
            position: 'fixed',
            top: 0,
            left: 0,
            right: 0,
            bottom: 0,
            backgroundColor: 'rgba(3, 7, 18, 0.95)',
            zIndex: 1000,
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
          }}
        >
          <div
            className="cyber-card"
            style={{
              width: '90%',
              maxWidth: '450px',
              textAlign: 'center',
              padding: '40px 30px',
              border: '2px solid var(--neon-green)',
              boxShadow: '0 0 35px rgba(34, 197, 94, 0.4)',
            }}
          >
            <h2 className="text-glow-green" style={{ color: 'var(--neon-green)', fontSize: '2rem', marginBottom: '10px', textTransform: 'uppercase' }}>
              💥 EVOLUÇÃO COMPLETA! 💥
            </h2>
            <p style={{ color: 'rgba(255,255,255,0.7)', fontSize: '1rem', marginBottom: '20px' }}>
              Seu pet alcançou um novo patamar de poder matemático!
            </p>

            <div style={{ fontSize: '7.5rem', margin: '20px 0' }} className="animate-float">
              {levelUpMessage.emoji}
            </div>

            <h3 style={{ fontSize: '1.6rem', color: '#fff', marginBottom: '6px' }}>
              {levelUpMessage.name}
            </h3>
            <p style={{ color: 'var(--neon-yellow)', fontWeight: 800, fontSize: '1.2rem', marginBottom: '30px' }}>
              NÍVEL ATUAL: {levelUpMessage.level}
            </p>

            <button
              className="cyber-btn"
              onClick={() => { setLevelUpMessage(null); }}
              style={{
                padding: '12px 30px',
                fontSize: '1rem',
                fontWeight: 800,
                width: '100%',
                background: 'rgba(34, 197, 94, 0.15)',
                borderColor: 'var(--neon-green)'
              }}
            >
              Continuar Treino ➔
            </button>
          </div>
        </div>
      )}
      {/* Accessibility screen reader announcements */}
      <div aria-live="polite" style={{ position: 'absolute', width: '1px', height: '1px', padding: 0, margin: '-1px', overflow: 'hidden', clip: 'rect(0, 0, 0, 0)', border: 0 }}>
        {screenReaderAnnouncement}
      </div>
    </div>
  );
};

import { createClient } from '@supabase/supabase-js';
import { mockDb, COSMETIC_ITEMS } from './mockDb';
import type { User, GameState, Pet, MathStatistic, TimelineEntry, Clan } from './mockDb';
import type {
  SupabaseUserRow,
  SupabaseGameStateRow,
  SupabasePetRow,
  SupabaseMathStatisticRow,
  SupabaseClanRow
} from './db/dbConfig';
import {
  STORAGE_KEYS,
  getStorageItem,
  setStorageItem
} from './db/dbConfig';
import { logger } from './logger';

/**
 * DATABASE SETUP SCHEMA FOR SUPABASE:
 * 
 * -- 1. Table: users
 * CREATE TABLE users (
 *   id TEXT PRIMARY KEY,
 *   username TEXT UNIQUE NOT NULL,
 *   password TEXT NOT NULL,
 *   role TEXT DEFAULT 'player',
 *   created_at TIMESTAMPTZ DEFAULT NOW()
 * );
 * 
 * -- 2. Table: game_states
 * CREATE TABLE game_states (
 *   user_id TEXT PRIMARY KEY REFERENCES users(id) ON DELETE CASCADE,
 *   campaign_stage INT DEFAULT 1,
 *   gems INT DEFAULT 0,
 *   aura_level INT DEFAULT 1,
 *   aura_xp INT DEFAULT 0,
 *   aura_color TEXT DEFAULT '#00ffcc',
 *   rebirths INT DEFAULT 0,
 *   current_zone TEXT DEFAULT 'forest',
 *   equipped_pet_id TEXT,
 *   active_auras TEXT[] DEFAULT '{}',
 *   total_play_time_seconds INT DEFAULT 0,
 *   purchased_cosmetics TEXT[] DEFAULT '{}',
 *   equipped_cosmetic_id TEXT,
 *   selected_operation TEXT DEFAULT 'multiplication',
 *   quest_wins INT DEFAULT 0,
 *   quest_criticals INT DEFAULT 0,
 *   quest_streak INT DEFAULT 0,
 *   claimed_quests TEXT[] DEFAULT '{}',
 *   active_class TEXT,
 *   skill_points INT DEFAULT 0,
 *   unlocked_skills TEXT[] DEFAULT '{}',
 *   clan_id TEXT,
 *   clan_contributions INT DEFAULT 0,
 *   updated_at TIMESTAMPTZ DEFAULT NOW()
 * );
 * 
 * -- 2.5. Table: clans
 * CREATE TABLE clans (
 *   id TEXT PRIMARY KEY,
 *   name TEXT NOT NULL,
 *   tag TEXT NOT NULL,
 *   motto TEXT,
 *   badge_emoji TEXT,
 *   members TEXT[] DEFAULT '{}',
 *   level INT DEFAULT 1,
 *   xp INT DEFAULT 0,
 *   leader_id TEXT,
 *   join_requests TEXT[] DEFAULT '{}'
 * );
 * 
 * -- 3. Table: pets
 * CREATE TABLE pets (
 *   id TEXT PRIMARY KEY,
 *   user_id TEXT REFERENCES users(id) ON DELETE CASCADE,
 *   pet_type_id TEXT NOT NULL,
 *   nickname TEXT NOT NULL,
 *   rarity TEXT NOT NULL,
 *   buff_type TEXT NOT NULL,
 *   buff_value REAL NOT NULL,
 *   level INT DEFAULT 1,
 *   stars INT DEFAULT 1,
 *   created_at TIMESTAMPTZ DEFAULT NOW()
 * );
 * 
 * -- 4. Table: math_statistics
 * CREATE TABLE math_statistics (
 *   id TEXT PRIMARY KEY,
 *   user_id TEXT REFERENCES users(id) ON DELETE CASCADE,
 *   question_key TEXT NOT NULL,
 *   incorrect_count INT DEFAULT 0,
 *   correct_count INT DEFAULT 0,
 *   total_time_taken_ms INT DEFAULT 0,
 *   UNIQUE(user_id, question_key)
 * );
 */

const SUPABASE_URL = (import.meta.env?.VITE_SUPABASE_URL as string) || '';
const SUPABASE_ANON_KEY = (import.meta.env?.VITE_SUPABASE_ANON_KEY as string) || '';

const isSupabaseEnabled = SUPABASE_URL.trim() !== '' && SUPABASE_ANON_KEY.trim() !== '';

export const supabase = isSupabaseEnabled
  ? createClient(SUPABASE_URL, SUPABASE_ANON_KEY)
  : null;

if (!isSupabaseEnabled) {
  console.warn(
    '🛡️ [BackendService] Supabase VITE_SUPABASE_URL and VITE_SUPABASE_ANON_KEY not configured.\n' +
    '🛡️ [BackendService] Running in Offline mode, utilizing LocalStorage mockDb.'
  );
}

// Helpers for data mapping
const mapDbToGameState = (row: SupabaseGameStateRow): GameState => {
  const rawEquipped = row.equipped_cosmetic_id || null;
  let equippedCosmetics: Record<string, string> = {};
  let equippedCosmeticId: string | null = null;
  let hasElitePass = false;
  let auraPassXp = 0;
  let claimedPassTiers: number[] = [];

  if (rawEquipped) {
    if (rawEquipped.startsWith('{')) {
      try {
        const parsed = JSON.parse(rawEquipped) as Record<string, any>;
        hasElitePass = (parsed.hasElitePass as boolean | undefined) ?? false;
        auraPassXp = (parsed.auraPassXp as number | undefined) ?? 0;
        claimedPassTiers = (parsed.claimedPassTiers as number[] | undefined) ?? [];

        equippedCosmetics = { ...parsed };
        delete equippedCosmetics.hasElitePass;
        delete equippedCosmetics.auraPassXp;
        delete equippedCosmetics.claimedPassTiers;

        const values = Object.values(equippedCosmetics);
        equippedCosmeticId = values.length > 0 ? values[0] : null;
      } catch (e) {
        console.error('Failed to parse equippedCosmetics JSON:', e);
      }
    } else {
      equippedCosmeticId = rawEquipped;
      const item = COSMETIC_ITEMS.find(c => c.id === rawEquipped);
      if (item) {
        equippedCosmetics = { [item.category]: rawEquipped };
      }
    }
  }

  const parseStringArray = (val: string[] | string | undefined): string[] => {
    if (!val) return [];
    if (Array.isArray(val)) return val;
    if (val.startsWith('{')) {
      try {
        return val.replace(/[{}]/g, '').split(',').map(s => s.trim().replace(/^"|"$/g, '')).filter(Boolean);
      } catch {
        return [];
      }
    }
    return [val];
  };

  return {
    userId: row.user_id,
    campaignStage: row.campaign_stage ?? 1,
    gems: row.gems ?? 0,
    auraLevel: row.aura_level ?? 1,
    auraXp: row.aura_xp ?? 0,
    auraColor: row.aura_color ?? '#00ffcc',
    rebirths: row.rebirths ?? 0,
    currentZone: row.current_zone ?? 'forest',
    equippedPetId: row.equipped_pet_id || null,
    activeAuras: parseStringArray(row.active_auras),
    totalPlayTimeSeconds: row.total_play_time_seconds ?? 0,
    purchasedCosmetics: parseStringArray(row.purchased_cosmetics),
    equippedCosmetics,
    equippedCosmeticId,
    selectedOperation: row.selected_operation ?? 'multiplication',
    questWins: row.quest_wins ?? 0,
    questCriticals: row.quest_criticals ?? 0,
    questStreak: row.quest_streak ?? 0,
    claimedQuests: parseStringArray(row.claimed_quests),
    classId: row.active_class || null,
    skillPoints: row.skill_points ?? 0,
    unlockedSkills: parseStringArray(row.unlocked_skills),
    clanId: row.clan_id || null,
    clanContributions: row.clan_contributions ?? 0,
    updatedAt: row.updated_at || new Date().toISOString(),
    hasElitePass,
    auraPassXp,
    claimedPassTiers,
  };
};

const mapGameStateToDb = (state: Partial<GameState>): Partial<SupabaseGameStateRow> => {
  const dbRow: Partial<SupabaseGameStateRow> = {};
  if (state.campaignStage !== undefined) dbRow.campaign_stage = state.campaignStage;
  if (state.gems !== undefined) dbRow.gems = state.gems;
  if (state.auraLevel !== undefined) dbRow.aura_level = state.auraLevel;
  if (state.auraXp !== undefined) dbRow.aura_xp = state.auraXp;
  if (state.auraColor !== undefined) dbRow.aura_color = state.auraColor;
  if (state.rebirths !== undefined) dbRow.rebirths = state.rebirths;
  if (state.currentZone !== undefined) dbRow.current_zone = state.currentZone;
  if (state.equippedPetId !== undefined) dbRow.equipped_pet_id = state.equippedPetId;
  if (state.activeAuras !== undefined) dbRow.active_auras = state.activeAuras;
  if (state.totalPlayTimeSeconds !== undefined) dbRow.total_play_time_seconds = state.totalPlayTimeSeconds;
  if (state.purchasedCosmetics !== undefined) dbRow.purchased_cosmetics = state.purchasedCosmetics;

  // Serialize equippedCosmetics and Aura Pass fields together
  const equippedJsonObj: Record<string, any> = { ...(state.equippedCosmetics || {}) };
  if (state.hasElitePass !== undefined) equippedJsonObj.hasElitePass = state.hasElitePass;
  if (state.auraPassXp !== undefined) equippedJsonObj.auraPassXp = state.auraPassXp;
  if (state.claimedPassTiers !== undefined) equippedJsonObj.claimedPassTiers = state.claimedPassTiers;

  dbRow.equipped_cosmetic_id = JSON.stringify(equippedJsonObj);

  if (state.selectedOperation !== undefined) dbRow.selected_operation = state.selectedOperation;
  if (state.questWins !== undefined) dbRow.quest_wins = state.questWins;
  if (state.questCriticals !== undefined) dbRow.quest_criticals = state.questCriticals;
  if (state.questStreak !== undefined) dbRow.quest_streak = state.questStreak;
  if (state.claimedQuests !== undefined) dbRow.claimed_quests = state.claimedQuests;
  if (state.classId !== undefined) dbRow.active_class = state.classId;
  if (state.skillPoints !== undefined) dbRow.skill_points = state.skillPoints;
  if (state.unlockedSkills !== undefined) dbRow.unlocked_skills = state.unlockedSkills;
  if (state.clanId !== undefined) dbRow.clan_id = state.clanId;
  if (state.clanContributions !== undefined) dbRow.clan_contributions = state.clanContributions;
  dbRow.updated_at = new Date().toISOString();
  return dbRow;
};

export const backendService = {
  isCloudConnected(): boolean {
    return isSupabaseEnabled && typeof window !== 'undefined' && window.navigator.onLine;
  },

  async syncCloudAndLocalState(userId: string): Promise<void> {
    if (!this.isCloudConnected()) {
      return;
    }
    try {
      logger.log('🔄 Sincronizando dados do Supabase para o armazenamento local...');
      const state = await this.getGameState(userId);
      const pets = await this.getPets(userId);
      const stats = await this.getMathStats(userId);

      if (state) {
        const localStatesRaw = localStorage.getItem('amq_game_states');
        const localStates = localStatesRaw
          ? JSON.parse(localStatesRaw) as GameState[]
          : [];
        const filteredStates = localStates.filter((s) => s.userId !== userId);
        filteredStates.push(state);
        localStorage.setItem('amq_game_states', JSON.stringify(filteredStates));
      }

      if (pets) {
        const localPetsRaw = localStorage.getItem('amq_pets');
        const localPets = localPetsRaw
          ? JSON.parse(localPetsRaw) as Pet[]
          : [];
        const filteredPets = localPets.filter((p) => p.userId !== userId);
        filteredPets.push(...pets);
        localStorage.setItem('amq_pets', JSON.stringify(filteredPets));
      }

      if (stats) {
        const localStatsRaw = localStorage.getItem('amq_stats');
        const localStats = localStatsRaw
          ? JSON.parse(localStatsRaw) as MathStatistic[]
          : [];
        const filteredStats = localStats.filter((s) => s.userId !== userId);
        filteredStats.push(...stats);
        localStorage.setItem('amq_stats', JSON.stringify(filteredStats));
      }
    } catch (err) {
      logger.error('❌ Falha ao sincronizar dados com o Supabase:', err);
      throw err;
    }
  },

  async buyCosmetic(userId: string, cosmeticId: string): Promise<GameState | null> {
    const cosmetic = COSMETIC_ITEMS.find(c => c.id === cosmeticId);
    if (!cosmetic) throw new Error('Item cosmético não encontrado.');

    const state = await this.getGameState(userId);
    if (!state) throw new Error('Estado do jogador não encontrado.');

    const purchased = state.purchasedCosmetics || [];
    if (purchased.includes(cosmeticId)) {
      throw new Error('Você já possui este cosmético.');
    }

    if (state.gems < cosmetic.cost) {
      throw new Error('Gemas insuficientes para comprar este cosmético.');
    }

    const updated = await this.updateGameState(userId, {
      gems: state.gems - cosmetic.cost,
      purchasedCosmetics: [...purchased, cosmeticId]
    });

    return updated;
  },

  async claimQuestReward(userId: string, questId: string, rewardGems: number): Promise<GameState | null> {
    const state = await this.getGameState(userId);
    if (!state) throw new Error('Estado do jogador não encontrado.');

    const claimed = state.claimedQuests || [];
    if (claimed.includes(questId)) {
      throw new Error('Recompensa de missão já resgatada.');
    }

    const updated = await this.updateGameState(userId, {
      gems: state.gems + rewardGems,
      claimedQuests: [...claimed, questId]
    });

    return updated;
  },

  // 1. User Queries & Management
  async getUsers(): Promise<User[]> {
    const client = supabase;
    if (isSupabaseEnabled && client) {
      try {
        console.log('[BackendService] Fetching users from Supabase...');
        const { data, error } = await client.from('users').select('*').returns<SupabaseUserRow[]>();
        if (error) throw error;
        return (data || []).map((u) => ({
          id: u.id,
          username: u.username,
          role: u.role,
          passwordHash: u.password ?? 'secured',
          createdAt: new Date().toISOString()
        }));
      } catch (err) {
        console.error('[BackendService] Supabase error in getUsers:', err);
      }
    }
    return mockDb.getUsers();
  },

  async createUser(username: string, passwordPlain: string, role: 'admin' | 'player', isActive: boolean = true): Promise<User | null> {
    const client = supabase;
    if (isSupabaseEnabled && client) {
      try {
        console.log(`[BackendService] Creating user: ${username} via Supabase Auth (tempClient)...`);
        const email = `${username.toLowerCase().trim()}@auramathquest.local`;

        // Create a temporary client so it doesn't overwrite/hijack the admin session
        const tempClient = createClient(SUPABASE_URL, SUPABASE_ANON_KEY, {
          auth: {
            persistSession: false,
            autoRefreshToken: false,
            detectSessionInUrl: false
          }
        });

        // 1. Sign up the user in Supabase Auth via the temp client
        const { data: authData, error: authError } = await tempClient.auth.signUp({
          email,
          password: passwordPlain,
          options: {
            data: {
              username: username.trim(),
              role: role
            }
          }
        });
        if (authError) throw authError;

        if (authData && authData.user) {
          const userId = authData.user.id;
          console.log(`[BackendService] Inserting public profile for user: ${username} with ID: ${userId}...`);

          // 2. Insert user profile via PRIMARY client (preserves logged-in admin session and executes with admin RLS permissions)
          const { error: userError } = await client.from('users').insert({
            id: userId,
            username: username.trim(),
            password: passwordPlain, // Keep plain text in users table so password trigger can update auth.users
            role
          }).returns<SupabaseUserRow[]>();
          if (userError) throw userError;

          if (role === 'player') {
            const defaultDbRow = mapGameStateToDb({
              userId,
              campaignStage: 1,
              gems: 0,
              auraLevel: 1,
              auraXp: 0,
              auraColor: '#00ffcc',
              rebirths: 0,
              currentZone: 'forest',
              equippedPetId: null,
              activeAuras: [],
              totalPlayTimeSeconds: 0,
              purchasedCosmetics: [],
              equippedCosmeticId: null,
              selectedOperation: 'multiplication',
              questWins: 0,
              questCriticals: 0,
              questStreak: 0,
              claimedQuests: [],
              classId: null,
              skillPoints: 0,
              unlockedSkills: [],
              clanId: null,
              clanContributions: 0,
            });
            defaultDbRow.user_id = userId;

            const { error: stateError } = await client.from('game_states').insert(defaultDbRow).returns<SupabaseGameStateRow[]>();
            if (stateError) throw stateError;
          }

          const newUser: User = {
            id: userId,
            username: username.trim(),
            role,
            passwordHash: 'secured',
            createdAt: new Date().toISOString(),
            isActive
          };

          // Mirror locally just in case
          mockDb.createUser(username, passwordPlain, role, isActive);
          return newUser;
        }
        return null;
      } catch (err) {
        console.error('[BackendService] Supabase error in createUser:', err);
        return null;
      }
    }
    return mockDb.createUser(username, passwordPlain, role, isActive);
  },

  async updateUser(userId: string, updates: Partial<User>): Promise<boolean> {
    const client = supabase;
    if (isSupabaseEnabled && client) {
      try {
        console.log(`[BackendService] Updating user: ${userId} in Supabase...`, updates);
        const dbUpdates: any = {};
        if (updates.username !== undefined) dbUpdates.username = updates.username;
        if (updates.passwordHash !== undefined) dbUpdates.password = updates.passwordHash;
        if (updates.role !== undefined) dbUpdates.role = updates.role;

        const { error } = await client.from('users').update(dbUpdates).eq('id', userId).returns<SupabaseUserRow[]>();
        if (error) throw error;
        mockDb.updateUser(userId, updates);
        return true;
      } catch (err) {
        console.error('[BackendService] Supabase error in updateUser:', err);
        return false;
      }
    }
    return mockDb.updateUser(userId, updates);
  },

  async deleteUser(userId: string): Promise<boolean> {
    const client = supabase;
    if (isSupabaseEnabled && client) {
      try {
        console.log(`[BackendService] Deleting user: ${userId} in Supabase...`);
        const { error } = await client.from('users').delete().eq('id', userId).returns<SupabaseUserRow[]>();
        if (error) throw error;
        mockDb.deleteUser(userId);
        return true;
      } catch (err) {
        console.error('[BackendService] Supabase error in deleteUser:', err);
        return false;
      }
    }
    return mockDb.deleteUser(userId);
  },

  // 2. Auth & Session
  async login(username: string, passwordPlain: string): Promise<User | null> {
    const client = supabase;
    if (isSupabaseEnabled && client) {
      try {
        console.log(`[BackendService] Logging in user: ${username} via Supabase Auth...`);
        const email = `${username.toLowerCase().trim()}@auramathquest.local`;

        const { data: authData, error: authError } = await client.auth.signInWithPassword({
          email,
          password: passwordPlain
        });
        if (authError) throw authError;

        if (authData && authData.user) {
          const { data, error } = await client
            .from('users')
            .select('*')
            .eq('id', authData.user.id)
            .returns<SupabaseUserRow[]>();
          if (error) throw error;

          if (data && data.length > 0) {
            const u = data[0];

            const loggedInUser: User = {
              id: u.id,
              username: u.username,
              role: u.role,
              passwordHash: 'secured',
              createdAt: new Date().toISOString(),
              isActive: true
            };

            // Sync locally to mockDb cache for offline/visual operations
            mockDb.createUser(u.username, passwordPlain, u.role, true);
            return loggedInUser;
          }
        }
        return null;
      } catch (err) {
        console.error('[BackendService] Supabase error in login:', err);
        return null;
      }
    }

    // Fallback authentication check ONLY when Supabase is completely disabled
    const user = mockDb.getUsers().find(u => u.username.toLowerCase() === username.toLowerCase()) || null;
    if (user && user.passwordHash === mockDb.mockHash(passwordPlain)) {
      if (user.isActive === false) return null;
      return user;
    }
    return null;
  },

  // Helper to migrate legacy board settings from localStorage to GameState / Supabase
  checkAndMigrateLegacyBoards(userId: string, state: GameState): GameState {
    if (typeof window === 'undefined') return state;
    const legacyEquipped = localStorage.getItem(`amq_runner_equipped_board_${userId}`);
    const legacyPurchasedRaw = localStorage.getItem(`amq_runner_purchased_boards_${userId}`);

    if (!legacyEquipped && !legacyPurchasedRaw) {
      return state;
    }

    console.log(`[BackendService] Migrating legacy runner board data for ${userId} to game state...`);

    let updated = false;
    const purchased = [...(state.purchasedCosmetics || [])];
    const equipped = { ...(state.equippedCosmetics || {}) };

    if (legacyPurchasedRaw) {
      try {
        const legacyPurchased = JSON.parse(legacyPurchasedRaw) as string[];
        legacyPurchased.forEach(board => {
          if (['light_skate', 'tron_bike', 'holo_board'].includes(board) && !purchased.includes(board)) {
            purchased.push(board);
            updated = true;
          }
        });
      } catch (e) {
        console.error('Failed to parse legacy boards JSON:', e);
      }
    }

    if (legacyEquipped && ['light_skate', 'tron_bike', 'holo_board'].includes(legacyEquipped)) {
      if (equipped.vehicle !== legacyEquipped) {
        equipped.vehicle = legacyEquipped;
        updated = true;
      }
    }

    if (updated) {
      state.purchasedCosmetics = purchased;
      state.equippedCosmetics = equipped;
      state.updatedAt = new Date().toISOString();

      // Update in local mockDb
      mockDb.updateGameState(userId, {
        purchasedCosmetics: purchased,
        equippedCosmetics: equipped
      });

      // Remove legacy keys
      localStorage.removeItem(`amq_runner_equipped_board_${userId}`);
      localStorage.removeItem(`amq_runner_purchased_boards_${userId}`);
    }

    return state;
  },

  // 3. Game State
  async getGameState(userId: string): Promise<GameState | null> {
    let state: GameState | null = null;

    const client = supabase;
    if (isSupabaseEnabled && client) {
      try {
        console.log(`[BackendService] Fetching game state for ${userId} from Supabase...`);
        const { data, error } = await client.from('game_states').select('*').eq('user_id', userId).returns<SupabaseGameStateRow[]>();
        if (error) throw error;

        const localState = mockDb.getGameState(userId);

        if (data && data.length > 0) {
          const dbState = mapDbToGameState(data[0]);
          if (localState) {
            // Merge local-only properties so they are never lost by cloud-only loads
            dbState.treats = localState.treats ?? 0;
            dbState.activeExpeditions = localState.activeExpeditions ?? [];
            dbState.fedBonusUntil = localState.fedBonusUntil;

            // Resolve conflicts: if local is newer than DB, sync local to DB
            const dbTime = new Date(dbState.updatedAt || 0).getTime();
            const localTime = new Date(localState.updatedAt || 0).getTime();
            if (localTime > dbTime) {
              console.log('🔄 [BackendService] Local state is newer. Syncing to Supabase...');
              const dbUpdates = mapGameStateToDb(localState);
              client.from('game_states').update(dbUpdates).eq('user_id', userId).returns<SupabaseGameStateRow[]>().then(({ error: sError }) => {
                if (sError) console.error('Error syncing local state to Supabase:', sError);
              });
              state = localState;
            }
          }
          if (!state) {
            // Sync to local mockDb
            mockDb.syncGameState(dbState);
            state = dbState;
          }
        } else if (localState) {
          // If not found in Cloud, initialize it
          const dbRow = mapGameStateToDb(localState);
          dbRow.user_id = userId;
          await client.from('game_states').insert(dbRow).returns<SupabaseGameStateRow[]>();
          state = localState;
        }
      } catch (err) {
        console.error('[BackendService] Supabase error in getGameState:', err);
      }
    }

    if (!state) {
      state = mockDb.getGameState(userId);
    }

    if (!state) {
      console.warn(`[BackendService] No game state found for ${userId}. Initializing default state...`);
      const defaultState: GameState = {
        userId,
        auraLevel: 1,
        auraXp: 0,
        auraColor: '#00ffcc',
        rebirths: 0,
        gems: 0,
        currentZone: 'forest',
        equippedPetId: null,
        activeAuras: [],
        totalPlayTimeSeconds: 0,
        updatedAt: new Date().toISOString(),
        purchasedCosmetics: [],
        equippedCosmeticId: null,
        selectedOperation: 'multiplication',
        questWins: 0,
        questCriticals: 0,
        questStreak: 0,
        claimedQuests: [],
        classId: null,
        skillPoints: 0,
        unlockedSkills: [],
        clanId: null,
        clanContributions: 0,
        campaignStage: 1,
        customTimeLimit: 15,
        masteryThreshold: 5,
        lockedOperations: [],
      };

      const gameStates = getStorageItem<GameState>(STORAGE_KEYS.GAME_STATES);
      gameStates.push(defaultState);
      setStorageItem(STORAGE_KEYS.GAME_STATES, gameStates);

      state = defaultState;

      // Sync default state to Supabase in background
      const client = supabase;
      if (isSupabaseEnabled && client) {
        const dbRow = mapGameStateToDb(defaultState);
        dbRow.user_id = userId;
        client.from('game_states').insert(dbRow).returns<SupabaseGameStateRow[]>().then(({ error: sError }) => {
          if (sError) console.error('[BackendService] Error inserting seeded state on getGameState:', sError);
        });
      }
    }

    if (state) {
      state = this.checkAndMigrateLegacyBoards(userId, state);
    }

    return state;
  },

  async updateGameState(userId: string, updates: Partial<GameState>): Promise<GameState | null> {
    const localState = mockDb.updateGameState(userId, updates);
    const client = supabase;
    if (isSupabaseEnabled && client) {
      try {
        console.log(`[BackendService] Updating game state for ${userId} in Supabase...`, updates);
        const dbUpdates = mapGameStateToDb(localState || updates);
        const { data, error } = await client
          .from('game_states')
          .update(dbUpdates)
          .eq('user_id', userId)
          .select()
          .returns<SupabaseGameStateRow[]>();

        if (error) throw error;

        if (data && data.length > 0) {
          const dbState = mapDbToGameState(data[0]);
          if (localState) {
            dbState.treats = localState.treats ?? 0;
            dbState.activeExpeditions = localState.activeExpeditions ?? [];
            dbState.fedBonusUntil = localState.fedBonusUntil;
          }
          return dbState;
        }
      } catch (err) {
        console.error('[BackendService] Supabase error in updateGameState:', err);
      }
    }
    return localState;
  },

  // 4. Pets Management
  async getPets(userId: string): Promise<Pet[]> {
    const localPets = mockDb.getPets(userId);
    const client = supabase;
    if (isSupabaseEnabled && client) {
      try {
        console.log(`[BackendService] Fetching pets for ${userId} from Supabase...`);
        const { data, error } = await client.from('pets').select('*').eq('user_id', userId).returns<SupabasePetRow[]>();
        if (error) throw error;

        const dbPets = (data || []).map(p => ({
          id: p.id,
          userId: p.user_id,
          petTypeId: p.pet_type_id,
          nickname: p.nickname,
          rarity: p.rarity,
          buffType: p.buff_type,
