      masteryThreshold: 5
    };
    setStorageItem(STORAGE_KEYS.GAME_STATES, [defaultState]);
    setStorageItem(STORAGE_KEYS.CLANS, []);
    setStorageItem(STORAGE_KEYS.STATS, []);
  });

  describe('clansDb', () => {
