  describe('statsDb.getMathProgress', () => {
    it('returns progressive unlocked tiers and mastered lists', () => {
      const stats: MathStatistic[] = [];
      // Mastery threshold is 5 correct answers
      for (let x = 2; x <= 9; x++) {
